// import React, { useState, useEffect } from "react";

import "./App.css";
import Summary from "../Summary/Summary";
import ItemCard from "../ItemCard/ItemCard";
import { Spinner } from "../Simple/Spinner";

const React = window.React;
const { useState, useEffect } = React;

export const App = () => {
  const [data, setData] = useState({ __loading: true });

  const fetchData = async () => {
    try {
      //e.g. http://localhost:3000/?data=rightmove_chesterfiled
      let fileNoExt = new URLSearchParams(window.location.search).get("data");

      const next_on = localStorage.getItem(`${fileNoExt}__next_on`);
      const last_attempt = localStorage.getItem(`${fileNoExt}__last_attempt`);
      const now = new Date();
      let cacheOpt;
      if (last_attempt && now - new Date(last_attempt) < 4000) {
        console.log("FORCE RELOAD"); // as user tried twice within 4s
        cacheOpt = "reload";
      } else if (next_on && new Date(next_on) > now) {
        console.log("Keep CACHED data, which is valid until: " + next_on);
        cacheOpt = "force-cache";
      } else {
        cacheOpt = "reload";
      }

      if (cacheOpt === "reload") {
        const spinner = document.querySelector("#x-spinner");
        if (spinner) spinner.style.color = "red";
      }

      const url = `https://hitchin.info/data/${fileNoExt}.json`;
      console.log(`Fetch data from server: ${url}`);
      const response = await fetch(url, { cache: cacheOpt });
      if (!response.ok) {
        throw new Error(`Failed to get data for: ${fileNoExt}`);
      }
      const data = await response.json();
      localStorage.setItem(`${fileNoExt}__next_on`, new Date(data.next_on).toISOString());
      localStorage.setItem(`${fileNoExt}__last_attempt`, new Date().toISOString());

      //DEBUG: data.items = data.items.slice(42, 44);
      // data.items[0].is_new = true;

      setData(data);
    } catch (error) {
      setData({ __error: `${error}` });
    }
  };
  useEffect(() => {
    fetchData();
  }, []);

  document.title = process.env.NODE_ENV === "development" ? "DEVELOPMENT" : data.region;

  if (data.__loading) {
    return (
      <main>
        <Spinner id="x-spinner" />
      </main>
    );
  } else if (data.__error) {
    return <main style={{ color: "red" }}>{data.__error}</main>;
  } else
    return (
      <main>
        <Summary data={data} />

        {data.items && data.items.map((item, index) => <ItemCard key={index} item={item} />)}
      </main>
    );
};

export default App;
